+/// Add two Legendre coefficient arrays.
+pub fn legadd(c1: &[f64], c2: &[f64]) -> Vec<f64> {
+    let len = c1.len().max(c2.len());
+    let mut result = vec![0.0; len];
+    for (i, &v) in c1.iter().enumerate() {
+        result[i] += v;
+    }
+    for (i, &v) in c2.iter().enumerate() {
+        result[i] += v;
+    }
+    result
