+/// Build a Legendre series from its roots.
+pub fn legfromroots(roots: &[f64]) -> Vec<f64> {
+    if roots.is_empty() {
+        return vec![1.0];
+    }
+    // Start with (x - r[0]) in Legendre basis: [-r[0], 1]
+    let mut result = vec![-roots[0], 1.0];
+    for &r in &roots[1..] {
+        let factor = vec![-r, 1.0];
+        result = legmul(&result, &factor);
+    }
+    result
